#include <iostream>
#include <string>

using namespace std;

class BankAccount {
private:
    int accountNumber;
    double balance;
public:
    // Parameterized Constructor
    BankAccount(int accNum, double initialBal) {
        accountNumber = accNum;
        balance = initialBal;
        cout << "Account " << accountNumber << " opened.\n";
    }

    // Method to deposit
    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            cout << "Deposited: $" << amount << "\n";
        }
    }

    // Method to withdraw
    void withdraw(double amount) {
        if (amount <= balance) {
            balance -= amount;
            cout << "Withdrew: $" << amount << "\n";
        } else {
            cout << "Insufficient funds!\n";
        }
    }

    // Display info
    void display() {
        cout << "Acc: " << accountNumber << " | Bal: $" << balance << "\n";
    }

    // Destructor
    ~BankAccount() {
        cout << "Account " << accountNumber << " closed.\n";
    }
};

int main() {
    cout << "--- Banking System ---\n";

    // Creating object
    BankAccount myAcc(101, 500.0);

    myAcc.deposit(200);
    myAcc.display();

    myAcc.withdraw(1000);
    myAcc.withdraw(100);

    myAcc.display();

    return 0;
} // Destructor called here
